import{_ as n,o as i,c as t,ag as r}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Kunden","description":"","frontmatter":{},"headers":[],"relativePath":"de/features/customers.md","filePath":"de/features/customers.md"}'),l={name:"de/features/customers.md"};function a(s,e,o,d,u,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="kunden" tabindex="-1">Kunden <a class="header-anchor" href="#kunden" aria-label="Permalink to &quot;Kunden&quot;">​</a></h1><p>Verwalten Sie Ihre vollständige Kundendatenbank. Jede Rechnung, jedes Angebot und jedes Projekt ist mit einem Kundendatensatz verknüpft.</p><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Die Kundenseite listet alle Ihre Kunden mit den wichtigsten Informationen auf einen Blick auf. Verwenden Sie Suche und Filter, um Kunden schnell zu finden.</p><h2 id="kunden-erstellen" tabindex="-1">Kunden erstellen <a class="header-anchor" href="#kunden-erstellen" aria-label="Permalink to &quot;Kunden erstellen&quot;">​</a></h2><ol><li>Gehen Sie zu <strong>Kunden &gt; Neuer Kunde</strong></li><li>Füllen Sie die Kundendetails aus: <ul><li><strong>Name</strong> — Firmen- oder Personenname (erforderlich)</li><li><strong>E-Mail</strong> — Kontakt-E-Mail für den Rechnungsversand</li><li><strong>Telefon</strong> — Kontakttelefonnummer</li><li><strong>Adresse</strong> — Straße, Postleitzahl, Stadt, Land</li><li><strong>USt.-Nummer</strong> — USt.-Registrierung des Kunden (für B2B)</li><li><strong>Kundennummer</strong> — Automatisch generiert oder benutzerdefiniert</li></ul></li><li>Klicken Sie auf <strong>Speichern</strong></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Sie können Kunden auch direkt beim Erstellen einer Rechnung oder eines Angebots anlegen — ohne die Seite verlassen zu müssen.</p></div><h2 id="kundendetailseite" tabindex="-1">Kundendetailseite <a class="header-anchor" href="#kundendetailseite" aria-label="Permalink to &quot;Kundendetailseite&quot;">​</a></h2><p>Die Kundendetailseite zeigt:</p><ul><li><strong>Kontaktinformationen</strong> — Alle gespeicherten Daten</li><li><strong>Rechnungsverlauf</strong> — Jede an diesen Kunden gesendete Rechnung</li><li><strong>Ausgabenverlauf</strong> — Mit diesem Kunden verknüpfte Ausgaben</li><li><strong>Projekte</strong> — Aktive und abgeschlossene Projekte</li><li><strong>Statistiken</strong> — Gesamtumsatz, ausstehender Saldo, durchschnittliche Zahlungsdauer</li></ul><h2 id="aktionen" tabindex="-1">Aktionen <a class="header-anchor" href="#aktionen" aria-label="Permalink to &quot;Aktionen&quot;">​</a></h2><ul><li><strong>Bearbeiten</strong> — Kundeninformationen aktualisieren</li><li><strong>Rechnung erstellen</strong> — Eine neue Rechnung mit diesem Kunden vorausgefüllt starten</li><li><strong>Angebot erstellen</strong> — Ein neues Angebot für diesen Kunden starten</li><li><strong>Archivieren</strong> — Ins Archiv verschieben (kann später wiederhergestellt werden)</li><li><strong>Löschen</strong> — Kunden dauerhaft entfernen</li></ul><h2 id="massenaktionen" tabindex="-1">Massenaktionen <a class="header-anchor" href="#massenaktionen" aria-label="Permalink to &quot;Massenaktionen&quot;">​</a></h2><p>Wählen Sie mehrere Kunden für:</p><ul><li><strong>Archivieren</strong> — Inaktive Kunden in großem Umfang archivieren</li><li><strong>Wiederherstellen</strong> — Archivierte Kunden zurückholen</li><li><strong>Löschen</strong> — Mehrere Kunden entfernen</li></ul><h2 id="schnellansicht" tabindex="-1">Schnellansicht <a class="header-anchor" href="#schnellansicht" aria-label="Permalink to &quot;Schnellansicht&quot;">​</a></h2><p>Am Desktop klicken Sie auf einen Kunden in der Liste, um das <strong>Schnellansicht</strong>-Seitenpanel zu öffnen. Dies zeigt wichtige Details und Aktionen, ohne die Liste zu verlassen:</p><ul><li>Zusammenfassung der Kundeninformationen</li><li>Neueste Rechnungen</li><li>Bearbeiten-Schaltfläche zum Öffnen der vollständigen Bearbeitungsseite</li></ul><h2 id="kunden-importieren" tabindex="-1">Kunden importieren <a class="header-anchor" href="#kunden-importieren" aria-label="Permalink to &quot;Kunden importieren&quot;">​</a></h2><p>Importieren Sie Ihre bestehende Kundendatenbank aus CSV:</p><ol><li>Gehen Sie zu <strong>Profil &gt; Import</strong></li><li>Wählen Sie <strong>Kunden</strong> als Datentyp</li><li>Laden Sie Ihre CSV-Datei hoch</li><li>Ordnen Sie Ihre CSV-Spalten den MyCompanyDesk-Feldern zu (Name, E-Mail, Adresse usw.)</li><li>Überprüfen Sie die Vorschau</li><li>Bestätigen Sie den Import</li></ol><h2 id="kunden-exportieren" tabindex="-1">Kunden exportieren <a class="header-anchor" href="#kunden-exportieren" aria-label="Permalink to &quot;Kunden exportieren&quot;">​</a></h2><p>Exportieren Sie Ihre Kundenliste als CSV von der Kundenseite (Pro-Tarif und höher).</p><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Halten Sie Kunden-E-Mails aktuell — sie werden für den Rechnungsversand verwendet</li><li>Verwenden Sie die Suchleiste für sofortigen unscharfen Abgleich über alle Kundenfelder</li><li>Setzen Sie Ihre wichtigsten Kunden als Favoriten für schnellen Zugriff</li><li>Weisen Sie USt.-Nummern zu, um Reverse-Charge bei B2B-Rechnungen zu ermöglichen</li></ul>',25)])])}const m=n(l,[["render",a]]);export{g as __pageData,m as default};
